import{_ as a,o as t,c as p,j as r,a as s,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"地狱纳米辅助改造：奥西里斯","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/地狱纳米辅助改造：奥西里斯.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/地狱纳米辅助改造：奥西里斯.md"}'),n={name:"4.资源分区/2.改造与功法/改造/4.综合类/地狱纳米辅助改造：奥西里斯/地狱纳米辅助改造：奥西里斯.md"};function o(b,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"地狱纳米辅助改造-奥西里斯",tabindex:"-1"},[s("地狱纳米辅助改造：奥西里斯 "),r("a",{class:"header-anchor",href:"#地狱纳米辅助改造-奥西里斯","aria-label":'Permalink to "地狱纳米辅助改造：奥西里斯"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),_('<h1 id="地狱纳米辅助改造-奥西里斯-1" tabindex="-1">地狱纳米辅助改造：奥西里斯 <a class="header-anchor" href="#地狱纳米辅助改造-奥西里斯-1" aria-label="Permalink to &quot;地狱纳米辅助改造：奥西里斯&quot;">​</a></h1><p>地狱纳米辅助改造：奥西里斯<br> “若审判终将降临，我愿成为天平的砝码——一端承载逝者的遗恨，另一端托起生者的黎明。”</p><p>这套装甲是古老神话与尖端科技的冷酷结晶。冥府之王奥西里斯的“生死轮回”象征，与天启基因工程的造物之力在此交汇。其纳米材质中嵌入了源自天神族（Celestial）的能量控制技术，使其能够汲取外界能量，实现自我修复与形态重构，如同奥西里斯自身的再生神话。每一片装甲都闪烁着幽蓝与暗金的微光，如同尼罗河的夜色倒映着永恒的审判。</p><p>D+600<br> 奥西里斯计划，曾是地狱攻略的序章，旨在筛选那足以驾驭审判机关“蝇王”的灵魂。如今，它演变为理想国超级士兵的基石。</p><p>【幽能适应性】<br> 植入体内的能量循环系统发出低沉的轰鸣，如同冥界之门开启的先兆。名为【幽能】的能量在你体内流转，其关键属性为智力+操控。</p><p>幽能使用: 战斗中，以自由动作引动一丝幽能，你基于操控属性的攻击便附加上一点幽邃的能量增强。<br> 幽能回复:<br> 在长休息后，幽能如冥河之水般充盈，你的幽能会恢复至上限。<br> 在短休息后，心神凝聚，进行一次能量关键属性的检定，恢复成功数点能量。<br> 【审判者】<br> 装甲的臂铠与手部关节发出细微的机械运作声，全新的攻击模式已然就绪。现在你可以【操控+器用+器用：奥西里斯+专注：精密操作】使用拳套进行肉搏攻击，每一次挥击都带着审判的重量。<br> 【适应性改造】<br> 身躯的大部分模块已被基础机械化取代。黑暗如同白昼，饮食与休憩已非必需。你获得了【无需饮食】、【无需休息】、【自适应短休】。眼部闪过幽蓝色的数据流光，这是新生的开始，你获得【灵感视觉】。</p><p>C+1200<br> 当幽能的洪流在你体内平稳奔涌，更深层次的改造蓄势待发。装甲表面的纹路似乎更加清晰，流淌着古埃及象形文字般的幽光。</p><p>【幽能异界】<br> 你的意志开辟出一处D级亚空间，一个10立方米，无法放入独立单位的储物空间。金属光泽的入口在你手心一闪而逝，迅捷动作间，物品存取自如，如同奥西里斯从冥府中取回失物。</p><p>【适应性改造+】<br> 模块升级，你获得了【自适应长休息】。</p><p>【再生者】<br> 源自天神族的能量控制技术被激活，纳米机器在装甲与你的肌体间穿梭。奥西里斯的适格者获得1点活体护甲和1点快速医疗（医疗点12）。受损的装甲如同被神力修复，伤口在幽能的滋养下迅速愈合。</p><p>【审判者+】<br> 攻击的精准度与自身的速度得到显著提升。现在，你的攻势如同审判之矛，迅捷而精准。你的攻击检定获得【连射】特性，且冲锋时，有效距离将取最大值计算，不容罪恶有丝毫喘息之机。</p><p>B+2400<br> 肉体的机械化之路已至终点。你无需再用冰冷的钢铁替换温热的血肉，已付出的代价足够沉重。此刻起的改造，皆为提升幽能的传输效率，释放更强大的力量。装甲的轮廓似乎更加流畅，能量流动的辉光也愈发凝练。</p><p>【审判者++】<br> 幽能输出模块发出强烈的嗡鸣，空间在你意志下扭曲。使用者获得C级的【传送攻击】，攻击倏忽而至，如同冥神穿梭生死界限，同时获得【吸血2】，以及最多将2点的严重伤害转为韧性伤害，从被审判者身上剥离生机。</p><p>【再生者+】<br> 不朽的神话在你的身躯上重演。替换上一级效果，你获得总共2点活体护甲以及2点的快速医疗（医疗点24）。即使面对毁灭性的打击，也能迅速重组，再生如初。</p><p>【幽能出力改造】<br> 当你以操控属性发动攻击时，幽能将彻底转化为纯粹的破坏能量，使你的攻击获得【能量武器】特性。环绕周身的幽能流形成可见的暗色光晕，这流动的能量使你获得C级【传送移动】，身形飘忽不定，如同行走于冥界的幽魂。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(n,[["render",o]]);export{f as __pageData,m as default};
